import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";

function Details() {
  const { id } = useParams();

  const [artisan, setArtisan] = useState(null);
  const [error, setError] = useState(null);

  const [formData, setFormData] = useState({
    name: "",
    email: "",
    subject: "",
    message: "",
  });

  useEffect(() => {
    fetch(`http://localhost:3080/api/artisans/${id}`)
      .then((res) => {
        if (!res.ok) {
          throw new Error("Artisan introuvable");
        }

        return res.json();
      })
      .then((data) => {
        console.log("Artisan reçu :", data);
        setArtisan(data);
      })
      .catch((error) => {
        console.error(error);
        setError("Impossible de charger l'artisan.");
      });
  }, [id]);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    console.log("Message envoyé :", formData);

    alert("Message envoyé avec succès.");

    setFormData({
      name: "",
      email: "",
      subject: "",
      message: "",
    });
  };

  if (error) {
    return (
      <main className="container py-5 text-center">
        <p className="text-danger">{error}</p>
      </main>
    );
  }

  if (!artisan) {
    return (
      <main className="container py-5 text-center">
        <p>Chargement...</p>
      </main>
    );
  }

  const note = Math.round(Number(artisan.Note));

  return (
    <main className="container py-5">
      <div className="card shadow border-0 mb-5">
        <div className="row g-0">
          <div className="col-12 col-md-5">
            <img
              src={artisan.Image || "/images/default-artisan.jpg"}
              alt={artisan.Nom}
              className="img-fluid h-100 w-100 object-fit-cover rounded-start"
            />
          </div>

          <div className="col-12 col-md-7">
            <div className="card-body p-4">
              <h1 className="card-title mb-4">{artisan.Nom}</h1>

              <p>
                <strong>Note :</strong>{" "}
                {"★".repeat(note)}
                {"☆".repeat(5 - note)}
              </p>

              <p>
                <strong>Spécialité :</strong>{" "}
                {artisan.Specialite || "Non renseignée"}
              </p>

              <p>
                <strong>Localisation :</strong> {artisan.Ville}
              </p>

              {(artisan.Site_web || artisan.Website) && (
                <p>
                  <strong>Site web :</strong>{" "}
                  <a
                    href={artisan.Site_web || artisan.Website}
                    target="_blank"
                    rel="noreferrer"
                  >
                    Visiter le site
                  </a>
                </p>
              )}

              <hr />

              <h2 className="h4 mb-3">À propos</h2>

              <p>
                {artisan.A_propos ||
                  artisan.Description ||
                  "Aucune description disponible."}
              </p>
            </div>
          </div>
        </div>
      </div>

      <div className="card shadow border-0">
        <div className="card-body p-4">
          <h2 className="mb-4">Contacter cet artisan</h2>

          <form onSubmit={handleSubmit}>
            <div className="row">
              <div className="col-12 col-md-6 mb-3">
                <label htmlFor="name" className="form-label">
                  Nom
                </label>

                <input
                  type="text"
                  id="name"
                  name="name"
                  className="form-control"
                  value={formData.name}
                  onChange={handleChange}
                  required
                />
              </div>

              <div className="col-12 col-md-6 mb-3">
                <label htmlFor="email" className="form-label">
                  Email
                </label>

                <input
                  type="email"
                  id="email"
                  name="email"
                  className="form-control"
                  value={formData.email}
                  onChange={handleChange}
                  required
                />
              </div>
            </div>

            <div className="mb-3">
              <label htmlFor="subject" className="form-label">
                Objet
              </label>

              <input
                type="text"
                id="subject"
                name="subject"
                className="form-control"
                value={formData.subject}
                onChange={handleChange}
                required
              />
            </div>

            <div className="mb-4">
              <label htmlFor="message" className="form-label">
                Message
              </label>

              <textarea
                id="message"
                name="message"
                rows="5"
                className="form-control"
                value={formData.message}
                onChange={handleChange}
                required
              ></textarea>
            </div>

            <button type="submit" className="btn btn-primary">
              Envoyer le message
            </button>
          </form>
        </div>
      </div>
    </main>
  );
}

export default Details;
